  ('aboriginal-f0899a01-moex-00523', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲無故使用乙之帳號密碼，登入乙之電子信箱窺探其私密信件。甲成立何罪？', '["刑法第358條入侵電腦罪", "刑法第359條取得他人電磁紀錄罪", "刑法第360條妨害電腦使用罪", "刑法第339條之3電腦詐欺罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "e6e107130816", "answer_pdf_sha1": "1c2f06e63016", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00524', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲騎乘機車，靠近走在巷子旁邊的乙，趁其不備，徒手用力拉扯乙的皮包，得手後加速逃逸。甲構成何罪？', '["竊盜罪", "搶奪罪", "準強盜罪", "強盜罪"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "e6e107130816", "answer_pdf_sha1": "1c2f06e63016", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
